public class StrangeSort {
    public static int[] strangeSortList(int[] arr) {
        if (arr.length == 0) {
            return new int[0]; // Return empty array for empty input
        }

        Arrays.sort(arr); // Sort the array
        List<Integer> result = new ArrayList<>();
        int left = 0; // Pointer for the minimum
        int right = arr.length - 1; // Pointer for the maximum

        while (left <= right) {
            if (left == right) {
                result.add(arr[left]); // Add the last remaining element
            } else {
                result.add(arr[left]); // Add the minimum
                result.add(arr[right]); // Add the maximum
            }
            left++;
            right--;
        }

        // Convert List<Integer> to int[]
        return result.stream().mapToInt(i -> i).toArray();
    }
}
